targets.expr:
range_last(
    sum(
        integrate(
            ((homePower_value < $peakPowerLimit) default 0)[1d:$energySampleInterval]
        ) / 3600
    )
)
-
range_last(
    sum(
        integrate(
            ((extPower_value{title!="", title !~ "$extBlocklist"} < $peakPowerLimit) default 0)[1d:$energySampleInterval]
        ) / 3600
    )
)
-
range_last(
    sum(
        integrate(
            ((auxPower_value{title!="", title !~ "$auxBlocklist"} < $peakPowerLimit) default 0)[1d:$energySampleInterval]
        ) / 3600
    )
)

sum(
    integrate(
        ((homePower_value < $peakPowerLimit) default 0)[1h:$energySampleInterval] offset -1h
    ) / 3600
)
-
sum(
    integrate(
        ((extPower_value{title!="", title !~ "$extBlocklist"} < $peakPowerLimit) default 0)[1h:$energySampleInterval] offset -1h
    ) / 3600
)
-
sum(
    integrate(
        ((auxPower_value{title!="", title !~ "$auxBlocklist"} < $peakPowerLimit) default 0)[1h:$energySampleInterval] offset -1h
    ) / 3600
)

sort_by_label(
    range_last(
        sum by (loadpoint)(
            integrate(
                ((chargePower_value{loadpoint!="", loadpoint !~ "$loadpointBlocklist"} < $peakPowerLimit) default 0)[1d:$energySampleInterval]
            ) / 3600
        )
    )
, "loadpoint")
